import Layout from "@/layouts/Layout.astro";
import Header from "@/components/Header.astro";
import Footer from "@/components/Footer.astro";
import Hero from "@/components/Hero.astro";
import Projects from "@/components/Projects.astro";
import Contact from "@/components/Contact.astro";
import { en } from "@/i18n/en";
import { zh } from "@/i18n/zh";
---

<Layout scrollSmooth>
  <Header />
  <main id="main-content" data-layout="index" class="app-layout">
    <Hero />

    <section
      id="about-section"
      class="border-t border-border pt-12 pb-6"
    >
      <div class="flex flex-col items-center gap-8 sm:flex-row sm:items-start">
        <div class="shrink-0">
          <img
            src="/assets/self1.webp"
            alt="Chen Judy"
            class="w-44 rounded-2xl object-cover shadow-md sm:w-52"
            loading="lazy"
          />
        </div>
        <div class="flex-1">
          <h2
            class="text-2xl font-semibold tracking-wide"
            data-lang-en={en.aboutTitle}
            data-lang-zh={zh.aboutTitle}
          >
            {en.aboutTitle}
          </h2>
          <p
            class="mt-4 leading-relaxed text-foreground/80"
            id="about-bio-en"
          >
            I'm the founder of <a href="https://illucio2.vercel.app/" target="_blank" rel="noopener noreferrer" class="text-accent underline decoration-dashed underline-offset-4 hover:decoration-solid">ILLUCIO</a> — using AI to turn complex text into interactive, dimensional articles you don't just read, but play. CS undergrad at Harbin Institute of Technology, MSc at National University of Singapore. I write code, build products, practice the sword, and believe in "playfulness".
          </p>
          <p
            class="mt-4 leading-relaxed text-foreground/80 hidden"
            id="about-bio-zh"
          >
            我是 <a href="https://illucio2.vercel.app/" target="_blank" rel="noopener noreferrer" class="text-accent underline decoration-dashed underline-offset-4 hover:decoration-solid">ILLUCIO</a> 创始人，用 AI 把复杂文本变成可以交互的立体文章——不只是读，而是上手玩。哈工大计算机本科，新加坡国立大学硕士。写代码，做产品，练剑，信仰"好玩儿主义"。
          </p>
        </div>
      </div>
    </section>

    <div class="border-t border-border">
      <Projects />
    </div>

    <div class="border-t border-border">
      <Contact />
    </div>
  </main>
  <Footer />
</Layout>

<script>
  function initLang() {
    const lang = localStorage.getItem("lang") || "en";
    applyLang(lang);
  }

  function applyLang(lang: string) {
    document.querySelectorAll("[data-lang-en]").forEach(el => {
      const text = lang === "zh"
        ? el.getAttribute("data-lang-zh")
        : el.getAttribute("data-lang-en");
      if (text) el.textContent = text;
    });

    const bioEn = document.getElementById("about-bio-en");
    const bioZh = document.getElementById("about-bio-zh");
    if (bioEn && bioZh) {
      bioEn.classList.toggle("hidden", lang === "zh");
      bioZh.classList.toggle("hidden", lang !== "zh");
    }
  }

  // Listen for custom language change events
  window.addEventListener("lang-change", ((e: CustomEvent) => {
    applyLang(e.detail.lang);
  }) as EventListener);

  initLang();
  document.addEventListener("astro:after-swap", initLang);
</script>

