---
import { getCollection } from "astro:content";
import type { GetStaticPathsOptions } from "astro";
import Main from "@/layouts/Main.astro";
import Layout from "@/layouts/Layout.astro";
import Header from "@/components/Header.astro";
import Footer from "@/components/Footer.astro";
import Card from "@/components/Card.astro";
import Pagination from "@/components/Pagination.astro";
import getUniqueTags from "@/utils/getUniqueTags";
import getPostsByTag from "@/utils/getPostsByTag";
import { getPostsForLang } from "@/utils/langUtils";
import { SITE } from "@/config";

export async function getStaticPaths({ paginate }: GetStaticPathsOptions) {
  const posts = await getCollection("blog");

  const langs = ["en", "zh"] as const;
  return langs.flatMap(lang => {
    const langPosts = getPostsForLang(posts, lang);
    const tags = getUniqueTags(langPosts);

    return tags.flatMap(({ tag, tagName }) => {
      const tagPosts = getPostsByTag(langPosts, tag);

      return paginate(tagPosts, {
        params: { tag: lang === "zh" ? `zh/${tag}` : tag },
        props: { tagName, lang },
        pageSize: SITE.postPerPage,
      });
    });
  });
}

const params = Astro.params;
const { tag } = params;
const { page, tagName, lang } = Astro.props;
const displayTag = tag?.replace(/^zh\//, "") ?? "";
---

<Layout title={`Tag: ${tagName} | ${SITE.title}`}>
  <Header />
  <Main
    pageTitle={[`Tag:`, `${tagName}`]}
    titleTransition={displayTag}
    pageDesc={lang === "zh" ? `所有带有 "${tagName}" 标签的文章。` : `All the articles with the tag "${tagName}".`}
  >
    <h1 slot="title" transition:name={displayTag}>{`Tag:${displayTag}`}</h1>
    <ul>
      {page.data.map(data => <Card {...data} />)}
    </ul>
  </Main>

  <Pagination {page} />

  <Footer noMarginTop={page.lastPage > 1} />
</Layout>

