import { getCollection } from "astro:content";
import Main from "@/layouts/Main.astro";
import Layout from "@/layouts/Layout.astro";
import Tag from "@/components/Tag.astro";
import Header from "@/components/Header.astro";
import Footer from "@/components/Footer.astro";
import getUniqueTags from "@/utils/getUniqueTags";
import { getPostsForLang } from "@/utils/langUtils";
import { SITE } from "@/config";

const posts = await getCollection("blog");

const enTags = getUniqueTags(getPostsForLang(posts, "en"));
const zhTags = getUniqueTags(getPostsForLang(posts, "zh"));
---

<Layout title={`Tags | ${SITE.title}`}>
  <Header />
  <Main pageTitle="Tags" pageDesc="All the tags used in posts.">
    <div data-lang-list="en">
      <ul class="flex flex-wrap gap-6">
        {enTags.map(({ tag, tagName }) => <Tag {tag} {tagName} lang="en" />)}
      </ul>
      {enTags.length === 0 && <p class="text-foreground/50 italic">No tags yet.</p>}
    </div>
    <div data-lang-list="zh" class="hidden">
      <ul class="flex flex-wrap gap-6">
        {zhTags.map(({ tag, tagName }) => <Tag {tag} {tagName} lang="zh" />)}
      </ul>
      {zhTags.length === 0 && <p class="text-foreground/50 italic">还没有标签。</p>}
    </div>
  </Main>
  <Footer />
</Layout>

<script>
  function initTagsLang() {
    const lang = localStorage.getItem("lang") || "en";
    applyLang(lang);
  }
  function applyLang(lang: string) {
    document.querySelectorAll<HTMLElement>("[data-lang-list]").forEach(el => {
      el.classList.toggle("hidden", el.dataset.langList !== lang);
    });
  }
  window.addEventListener("lang-change", ((e: CustomEvent) => {
    applyLang(e.detail.lang);
  }) as EventListener);
  initTagsLang();
  document.addEventListener("astro:after-swap", initTagsLang);
</script>

import { defineCollection, z } from "astro:content";
import { glob } from "astro/loaders";
import { SITE } from "@/config";

export const BLOG_PATH = "src/data/blog";

const blog = defineCollection({
  loader: glob({ pattern: "**/[^_]*.md", base: `./${BLOG_PATH}` }),
  schema: ({ image }) =>
    z.object({
      author: z.string().default(SITE.author),
      pubDatetime: z.date(),
      modDatetime: z.date().optional().nullable(),
      title: z.string(),
      featured: z.boolean().optional(),
      draft: z.boolean().optional(),
      category: z.enum(["notes", "collections"]).default("notes"),
      tags: z.array(z.string()).default(["others"]),
      ogImage: image().or(z.string()).optional(),
      lang: z.enum(["en", "zh"]).default("en"),
      description: z.string(),
      canonicalURL: z.string().optional(),
      externalUrl: z.string().optional(),
      hideEditPost: z.boolean().optional(),
      timezone: z.string().optional(),
    }),
});

export const collections = { blog };

